import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { Input, Btn, toast } from '../components/ui';
import { Lock, Mail, ArrowRight } from 'lucide-react';

const DEMO_USERS = []; // Removed for production security

export default function Login() {
  const { login, loading } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) {
      toast('Please enter email and password', 'warning');
      return;
    }
    const result = await login(email, password);
    if (!result.ok) {
      toast(result.error || 'Login failed', 'error');
    }
  };

  // Demo logins have been removed for production security

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <div className="logo-icon">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
              <circle cx="9" cy="7" r="4" />
              <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
              <path d="M16 3.13a4 4 0 0 1 0 7.75" />
            </svg>
          </div>
          <h1>UniHRM</h1>
          <p>University Human Resource Management</p>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ position: 'relative' }}>
            <Input
              label="Email Address"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
              id="login-email"
            />
          </div>
          <div style={{ position: 'relative' }}>
            <Input
              label="Password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
              id="login-password"
            />
          </div>
          <Btn
            type="submit"
            loading={loading}
            style={{
              width: '100%',
              padding: '10px 20px',
              fontSize: 14,
              fontWeight: 600,
              marginTop: 4,
              background: 'linear-gradient(135deg, var(--primary) 0%, var(--primary) 100%)',
              boxShadow: '0 4px 14px rgba(27, 110, 243, 0.35)',
              borderRadius: '6px',
              letterSpacing: '-0.01em',
            }}
          >
            Sign In <ArrowRight size={16} />
          </Btn>
        </form>
      </div>
    </div>
  );
}
